const conversationSummary = Context.getVariable("conversationSummary");
const customerPhoneNumber = Context.getVariable("customerPhoneNumber");
const customerEmailAddress = Context.getVariable("customerEmailAddress");
const customerOrderNumber = Context.getVariable("customerOrderNumber");

const escalation_data = `Customer Information:
${customerPhoneNumber || 'N/A'}
${customerEmailAddress || 'N/A'}
${customerOrderNumber || 'N/A'}

Conversation Summary:
${conversationSummary || 'N/A'}`;

Context.setVariable("escalation_data", escalation_data);
